import configparser
import os

def serialize(config, path):
    """Save the configuration to a file, supporting multiline values with continuation lines."""
    with open(path, 'w') as f:
        for section in config.sections():
            f.write(f"[{section}]\n")
            for key, value in config[section].items():
                lines = value.splitlines()
                f.write(f"{key} = {lines[0]}\n")
                for line in lines[1:]:
                    f.write(f"\t{line}\n")

def main():
    # Create configuration with multiline values and multiple sections
    config = configparser.ConfigParser()
    config['General'] = {
        'version': '1.0',
        'enabled': 'yes',
        'description': 'First line\n    Second line (indented)\nThird line'
    }
    config['Section1'] = {
        'key1': 'value1'
    }
    config['User'] = {
        'name': 'Alice',
        'email': 'alice@example.com'
    }
    path = 'test_scaled.ini'
    serialize(config, path)
    # Verify
    if os.path.exists(path):
        with open(path, 'r') as f:
            content = f.read()
        print('Configuration file content:')
        print(content)
    else:
        print('Failed to create configuration file.')

if __name__ == '__main__':
    main()
